"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["518255"],{355347(e){e.exports=JSON.parse('{"tag":{"label":"ocean","permalink":"/dst-api-webdocs/docs/tags/ocean","allTagsPath":"/dst-api-webdocs/docs/tags","count":35,"items":[{"id":"game-scripts/prefabs/boatlip","title":"Boatlip","description":"A visual, non-physical ground-decor entity used to animate boat lips at waterline transitions in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatlip"},{"id":"game-scripts/prefabs/chum","title":"Chum","description":"A throwable fishing bait item that spawns chum or a green splash effect depending on terrain, and creates an AOE when thrown into ocean tiles.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chum"},{"id":"game-scripts/prefabs/crabking_claw","title":"Crabking Claw","description":"Handles the crab king\'s claw entity as a combat-capable, ocean-bound minion with autonomous behavior and shadow linkage.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/crabking_claw"},{"id":"game-scripts/components/messagebottlemanager","title":"Messagebottlemanager","description":"Manages message bottle treasure hunts and hermit crab interactions in DST\'s ocean world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/messagebottlemanager"},{"id":"game-scripts/brains/miniboatlanternbrain","title":"Miniboatlanternbrain","description":"Controls the movement behavior of a small lantern-carrying entity that navigates ocean terrain using a wander-based AI.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/miniboatlanternbrain"},{"id":"game-scripts/components/ocean","title":"Ocean","description":"Manages ocean surface wave direction and speed for rendering or simulation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ocean"},{"id":"game-scripts/map/ocean_gen","title":"Ocean Gen","description":"Provides procedural generation functions for ocean tile placement, terrain smoothing, set piece placement, and entity population within ocean world regions.","permalink":"/dst-api-webdocs/docs/game-scripts/map/ocean_gen"},{"id":"game-scripts/map/ocean_gen_config","title":"Ocean Gen Config","description":"Contains configuration parameters for procedural ocean tile generation, including depth thresholds, noise settings, and elevation mapping for ocean terrain blending.","permalink":"/dst-api-webdocs/docs/game-scripts/map/ocean_gen_config"},{"id":"game-scripts/map/ocean_retrofit_island","title":"Ocean Retrofit Island","description":"A map-generation utility module that inserts ocean-based setpieces (moon islands, hermit islands, crab kings, waterlog biomes, monkey islands) into an existing world by validating terrain constraints and adding topology nodes.","permalink":"/dst-api-webdocs/docs/game-scripts/map/ocean_retrofit_island"},{"id":"game-scripts/ocean_util","title":"Ocean Util","description":"Provides utility functions for ocean-related game logic, including tile querying, wave spawning, creature flight state management, entity sinking, and shore point detection.","permalink":"/dst-api-webdocs/docs/game-scripts/ocean_util"},{"id":"game-scripts/prefabs/oceanfish","title":"Oceanfish","description":"Generates both underwater swimming fish entities and their corresponding inventory item versions used in ocean fishing and cooking, including lifecycle management, prey behavior, and fire-suppression capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfish"},{"id":"game-scripts/components/oceanfishable","title":"Oceanfishable","description":"Manages the fishable state and behavior of ocean creatures when interacting with fishing rods, including stamina-based struggle mechanics and movement speed adjustments based on line tension.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishable"},{"id":"game-scripts/prefabs/oceanfishableflotsam","title":"Oceanfishableflotsam","description":"Represents a floating object in the ocean that can be caught with fishing rods and later fished up for loot or salvaged with a winch.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishableflotsam"},{"id":"game-scripts/brains/oceanfishbrain","title":"Oceanfishbrain","description":"Controls the AI behavior of ocean-dwelling fish entities, including feeding, fishing hook interactions, fleeing, and wandering.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/oceanfishbrain"},{"id":"game-scripts/prefabs/oceanfishinglure","title":"Oceanfishinglure","description":"Generates ocean fishing lure prefabs with configurable appearance, data, and behavior for use in the Ocean Fishing subsystem.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishinglure"},{"id":"game-scripts/components/oceanfishingtackle","title":"Oceanfishingtackle","description":"Manages casting data and lure configuration for ocean fishing mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishingtackle"},{"id":"game-scripts/map/static_layouts/oceanmonument","title":"Oceanmonument","description":"Defines the static layout data for the Ocean Monument map room using Tiled JSON format, including tile layer configurations and object placements for ocean-based encounters.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/oceanmonument"},{"id":"game-scripts/components/oceanthrowable","title":"Oceanthrowable","description":"Manages the attachment and configuration of the complexprojectile component for entities intended to be thrown into ocean water.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanthrowable"},{"id":"game-scripts/components/oceantrawler","title":"Oceantrawler","description":"Manages the catching, storage, and release of ocean fish in a trawler net, including timing-based collection while sleeping, overflow handling, and animation synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceantrawler"},{"id":"game-scripts/prefabs/oceantreenut","title":"Oceantreenut","description":"A salvageable ocean object that periodically attempts to grow into an Oceantree when submerged and conditions are met.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceantreenut"},{"id":"game-scripts/map/static_layouts/oceanwhirlbigportal","title":"Oceanwhirlbigportal","description":"A static map layout definition for the Ocean Whirl big portal structure, containing tile data and object groups used by the world generator.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/oceanwhirlbigportal"},{"id":"game-scripts/prefabs/oceanwhirlbigportal","title":"Oceanwhirlbigportal","description":"Defines the ocean whirlpool migration portal (entry) and the exit pool prefab, handling world migration, visual effects, wave blocking, and loot distribution.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanwhirlbigportal"},{"id":"game-scripts/prefabs/oceanwhirlportal","title":"Oceanwhirlportal","description":"Spawnable ocean teleportation structure that detects boats within range and teleports them to a paired exit portal, applying wake effects and watery protection.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanwhirlportal"},{"id":"game-scripts/components/oceanwhirlportalphysics","title":"Oceanwhirlportalphysics","description":"Simulates physics forces (pull and radial rotation) on entities near an ocean whirlpool portal, and handles interaction with static objects and winch targets.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanwhirlportalphysics"},{"id":"game-scripts/components/schoolspawner","title":"Schoolspawner","description":"Spawns fish schools and triggers special ocean predators like gnarwails and sharks in oceanic regions based on player proximity and environmental conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/schoolspawner"},{"id":"game-scripts/stategraphs/SGoceanfish","title":"Sgoceanfish","description":"Defines the state machine for ocean-dwelling fish entities, handling behaviors such as breaching, biting fishing hooks, and exiting water.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGoceanfish"},{"id":"game-scripts/scenarios/sunkenchest_oceanmonument","title":"Sunkenchest Oceanmonument","description":"Defines loot configuration and initialization logic for ocean monument sunken chests in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/sunkenchest_oceanmonument"},{"id":"game-scripts/prefabs/trident","title":"Trident","description":"A magical trident that enables\u8FDC\u7A0B wave-spawned explosions on water and interacts with fish, plants, and structures in the ocean.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trident"},{"id":"game-scripts/map/waterlog_worldgen","title":"Waterlog Worldgen","description":"Generates waterlog terrain features and marker entities in ocean regions during world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/waterlog_worldgen"},{"id":"game-scripts/prefabs/wave","title":"Wave","description":"Simulates an ocean wave entity that moves, interacts with boats and items, and triggers splash effects upon collision or contact with land.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wave"},{"id":"game-scripts/prefabs/wave_shore","title":"Wave Shore","description":"Creates a background visual effect entity representing shore wave animations that dynamically adapt based on terrain adjacency and orientation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wave_shore"},{"id":"game-scripts/components/wavemanager","title":"Wavemanager","description":"Manages procedural spawning of ocean wave visual effects (shimmers and shore waves) near the player based on terrain type and distance from the camera.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wavemanager"},{"id":"game-scripts/prefabs/waveyjones","title":"Waveyjones","description":"Manages the behavior and lifecycle of Wavey Jones and its associated parts (arms, hands, hand art, and marker) in the Dangerous Sea event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waveyjones"},{"id":"game-scripts/prefabs/wobster","title":"Wobster","description":"Defines prefabs for wobster creatures (sheller and moonglass variants) in both ocean and land forms, including their components, state graphs, brains, and lifecycle behaviors such as fishing, landing, death, cooking, and seasonal mutation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wobster"},{"id":"game-scripts/brains/wobsterbrain","title":"Wobsterbrain","description":"AI controller for the Wobster entity that manages its behavior while fishing, including struggling when hooked, returning home during the day, and interacting with fishing lures.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wobsterbrain"}],"unlisted":false}}')}}]);